record.field:
campaign = env.ref('dojo_marketing.campaign_member_trial', raise_if_not_found=False)
if not campaign:
    log('dojo_marketing: campaign_member_trial not found, skipping card generation')
else:
    campaign._update_cards([('id', 'in', records.ids)])
    base_url = env['ir.config_parameter'].sudo().get_str('web.base.url', default='')
    for record in records:
        card = env['card.card'].search([
            ('campaign_id', '=', campaign.id),
            ('res_id', '=', record.id),
        ], limit=1)
        if card and record.partner_id.email:
            card_url = '%s%s' % (base_url, card._get_card_url())
            record.message_post(
                body='<p>Welcome to Dojang! Your trial membership card is ready.</p><p><a href="%s">View your card</a></p>' % card_url,
                subject='Your Dojang Trial Membership Card',
                message_type='email',
                subtype_xmlid='mail.mt_comment',
                partner_ids=[record.partner_id.id],
            )

